<?php
$pageTitle='PWA Settings';
require_once dirname(__DIR__,2) . '/includes/functions.php';
erpGuard('pwa_settings');
$pdo=getDB();
if($_SERVER['REQUEST_METHOD']==='POST'){
  try{
    $action=(string)($_POST['action']??'save');
    if($action==='install'){$count=installPwaDefaults($pdo);flash('success','PWA defaults installed/updated: '.$count);}
    else{
      $keys=['pwa_app_name','pwa_short_name','pwa_theme_color','pwa_background_color','pwa_display_mode','pwa_start_url','pwa_offline_page','pwa_service_worker_enabled','mobile_install_prompt_enabled','mobile_offline_mode_enabled','push_notifications_enabled','push_vapid_public_key','push_vapid_private_key','mobile_app_version','mobile_cache_version'];
      foreach($keys as $k){saveSetting($k,(string)($_POST[$k]??''));}
      installPwaDefaults($pdo);
      flash('success','PWA settings saved.');
    }
  }catch(Throwable $e){recordSystemError($pdo,$e,['page'=>'pwa-settings']);flash('error',$e->getMessage());}
  redirect(ADMIN_URL.'/erp/pwa-settings.php');
}
$assets=$pdo->query('SELECT * FROM '.table('pwa_cache_assets').' ORDER BY is_required DESC,asset_url LIMIT 150')->fetchAll();
$shortcuts=$pdo->query('SELECT * FROM '.table('pwa_app_shortcuts').' ORDER BY sort_order,shortcut_name LIMIT 100')->fetchAll();
include dirname(__DIR__).'/header.php';
?>
<div class="d-flex flex-wrap justify-content-between align-items-end gap-3 mb-4"><div><div class="erp-kicker">Installable Web App</div><h2 class="h4 mb-1">PWA Settings</h2><p class="text-secondary mb-0">Configure manifest, service worker, offline page, cache assets and app shortcuts.</p></div><form method="post"><input type="hidden" name="action" value="install"><button class="btn btn-brand">Install Defaults</button></form></div>
<div class="row g-4"><div class="col-xl-4"><form method="post" class="card-admin p-4"><h2 class="h5 mb-3">Manifest Settings</h2><input class="form-control mb-2" name="pwa_app_name" value="<?php echo esc(setting('pwa_app_name',setting('shop_name','ERP').' ERP')); ?>" placeholder="App name"><input class="form-control mb-2" name="pwa_short_name" value="<?php echo esc(setting('pwa_short_name','ERP')); ?>" placeholder="Short name"><input class="form-control mb-2" name="pwa_theme_color" value="<?php echo esc(setting('pwa_theme_color','#0f172a')); ?>" placeholder="#0f172a"><input class="form-control mb-2" name="pwa_background_color" value="<?php echo esc(setting('pwa_background_color','#ffffff')); ?>" placeholder="#ffffff"><select class="form-select mb-2" name="pwa_display_mode"><option value="standalone" <?php echo setting('pwa_display_mode','standalone')==='standalone'?'selected':''; ?>>standalone</option><option value="fullscreen" <?php echo setting('pwa_display_mode','standalone')==='fullscreen'?'selected':''; ?>>fullscreen</option><option value="browser" <?php echo setting('pwa_display_mode','standalone')==='browser'?'selected':''; ?>>browser</option></select><input class="form-control mb-2" name="pwa_start_url" value="<?php echo esc(setting('pwa_start_url','/mobile/index.php')); ?>"><input class="form-control mb-2" name="pwa_offline_page" value="<?php echo esc(setting('pwa_offline_page','/offline.php')); ?>"><div class="row g-2"><div class="col-6"><select class="form-select" name="pwa_service_worker_enabled"><option value="1" <?php echo setting('pwa_service_worker_enabled','1')==='1'?'selected':''; ?>>SW on</option><option value="0" <?php echo setting('pwa_service_worker_enabled','1')==='0'?'selected':''; ?>>SW off</option></select></div><div class="col-6"><select class="form-select" name="mobile_offline_mode_enabled"><option value="1" <?php echo setting('mobile_offline_mode_enabled','1')==='1'?'selected':''; ?>>Offline on</option><option value="0" <?php echo setting('mobile_offline_mode_enabled','1')==='0'?'selected':''; ?>>Offline off</option></select></div></div><select class="form-select my-2" name="mobile_install_prompt_enabled"><option value="1" <?php echo setting('mobile_install_prompt_enabled','1')==='1'?'selected':''; ?>>Install prompt enabled</option><option value="0" <?php echo setting('mobile_install_prompt_enabled','1')==='0'?'selected':''; ?>>Install prompt disabled</option></select><select class="form-select mb-2" name="push_notifications_enabled"><option value="1" <?php echo setting('push_notifications_enabled','1')==='1'?'selected':''; ?>>Push enabled</option><option value="0" <?php echo setting('push_notifications_enabled','1')==='0'?'selected':''; ?>>Push disabled</option></select><input class="form-control mb-2" name="push_vapid_public_key" value="<?php echo esc(setting('push_vapid_public_key','')); ?>" placeholder="VAPID public key"><input class="form-control mb-2" name="push_vapid_private_key" value="<?php echo esc(setting('push_vapid_private_key','')); ?>" placeholder="VAPID private key"><input class="form-control mb-2" name="mobile_app_version" value="<?php echo esc(setting('mobile_app_version','1.0.0')); ?>"><input class="form-control mb-3" name="mobile_cache_version" value="<?php echo esc(setting('mobile_cache_version','v1')); ?>"><button class="btn btn-brand w-100">Save Settings</button></form></div><div class="col-xl-8"><div class="table-wrap table-responsive mb-4"><h2 class="h5 mb-3">Cache Assets</h2><table class="table"><thead><tr><th>Asset</th><th>Type</th><th>Strategy</th><th>Status</th></tr></thead><tbody><?php foreach($assets as $a): ?><tr><td><strong><?php echo esc($a['asset_number']); ?></strong><div class="small text-secondary"><?php echo esc($a['asset_url']); ?></div></td><td><?php echo esc($a['asset_type']); ?></td><td><?php echo esc($a['cache_strategy']); ?></td><td><span class="badge bg-<?php echo esc(statusTone($a['status'])); ?>"><?php echo esc($a['status']); ?></span></td></tr><?php endforeach; ?></tbody></table></div><div class="table-wrap table-responsive"><h2 class="h5 mb-3">App Shortcuts</h2><table class="table"><thead><tr><th>Shortcut</th><th>URL</th><th>Enabled</th></tr></thead><tbody><?php foreach($shortcuts as $s): ?><tr><td><strong><?php echo esc($s['shortcut_name']); ?></strong><div class="small text-secondary"><?php echo esc($s['description']); ?></div></td><td><?php echo esc($s['shortcut_url']); ?></td><td><?php echo $s['is_enabled']?'Yes':'No'; ?></td></tr><?php endforeach; ?></tbody></table></div></div></div>
<?php include dirname(__DIR__).'/footer.php'; ?>